import * as React from "react"
import * as AccordionPrimitive from "@radix-ui/react-accordion"
import { Plus, X } from "lucide-react"

import { cn } from "@/lib/utils"
import "./accordion.css"

function Accordion({
  className,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Root>) {
  return (
    <AccordionPrimitive.Root
      data-slot="accordion"
      className={cn("flex flex-col gap-[var(--layout-gap-sm)]", className)}
      {...props}
    />
  )
}

function AccordionItem({
  className,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Item>) {
  return (
    <AccordionPrimitive.Item
      data-slot="accordion-item"
      className={cn(
        "accordion-item rounded-[var(--layout-radius-md)] overflow-hidden",
        className
      )}
      {...props}
    />
  )
}

function AccordionTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Trigger>) {
  return (
    <AccordionPrimitive.Header data-slot="accordion-header" className="flex">
      <AccordionPrimitive.Trigger
        data-slot="accordion-trigger"
        className={cn(
          "accordion-trigger flex flex-1 items-center justify-between min-h-[var(--layout-size-lg)] px-[var(--layout-padding-lg)] py-[var(--layout-padding-md)] text-content-body font-accent cursor-pointer focus-visible:outline-none",
          className
        )}
        {...props}
      >
        <span>{children}</span>
        <span className="accordion-icon shrink-0 [&_svg]:h-[var(--layout-size-xs)] [&_svg]:w-[var(--layout-size-xs)]">
          <Plus className="accordion-icon-plus" />
          <X className="accordion-icon-x" />
        </span>
      </AccordionPrimitive.Trigger>
    </AccordionPrimitive.Header>
  )
}

function AccordionContent({
  className,
  children,
  ...props
}: React.ComponentProps<typeof AccordionPrimitive.Content>) {
  return (
    <AccordionPrimitive.Content
      data-slot="accordion-content"
      className={cn("accordion-content overflow-hidden", className)}
      {...props}
    >
      <div className="accordion-content-inner px-[var(--layout-padding-lg)] pb-[var(--layout-padding-lg)] text-content-body">
        {children}
      </div>
    </AccordionPrimitive.Content>
  )
}

export { Accordion, AccordionItem, AccordionTrigger, AccordionContent }

/* ================================================================
 * ACCORDION — Item, Trigger, Icon & Content Styles
 * Structure (flex, padding, radius, gap) lives in accordion.tsx.
 * Theming (colors, borders, transitions, animation) lives here.
 * ================================================================ */

/* --------------------------------
 * Item — card background
 * -------------------------------- */
.accordion-item {
  background-color: var(--background-neutral-faint-default);
}

/* --------------------------------
 * Trigger — text color + states
 * -------------------------------- */
.accordion-trigger {
  color: var(--text-base-strong);
}

.accordion-trigger:hover {
  color: var(--text-base-bolder);
}

.accordion-trigger[data-disabled] {
  color: var(--text-disabled);
  cursor: default;
  pointer-events: none;
}

/* --------------------------------
 * Trigger — focus ring
 * -------------------------------- */
.accordion-trigger:focus-visible {
  box-shadow: 0 0 0 2px var(--background-base), 0 0 0 4px var(--border-selected);
}

/* --------------------------------
 * Icon — toggle Plus/X via data-state
 * -------------------------------- */
.accordion-icon {
  color: var(--text-base-moderate);
}

.accordion-trigger[data-state="closed"] .accordion-icon-x {
  display: none;
}

.accordion-trigger[data-state="open"] .accordion-icon-plus {
  display: none;
}

.accordion-trigger[data-disabled] .accordion-icon {
  color: var(--text-disabled);
}

/* --------------------------------
 * Content — height animation
 * Uses Radix CSS variable --radix-accordion-content-height
 * -------------------------------- */
.accordion-content[data-state="open"] {
  animation: accordion-expand 250ms ease;
}

.accordion-content[data-state="closed"] {
  animation: accordion-collapse 250ms ease;
}

@keyframes accordion-expand {
  from {
    height: 0;
  }
  to {
    height: var(--radix-accordion-content-height);
  }
}

@keyframes accordion-collapse {
  from {
    height: var(--radix-accordion-content-height);
  }
  to {
    height: 0;
  }
}

/* --------------------------------
 * Content — text color
 * -------------------------------- */
.accordion-content-inner {
  color: var(--text-base-moderate);
}

/* --------------------------------
 * Reduced motion — slow to 400ms (project pattern)
 * -------------------------------- */
@media (prefers-reduced-motion: reduce) {
  .accordion-content[data-state="open"],
  .accordion-content[data-state="closed"] {
    animation-duration: 400ms;
    animation-timing-function: linear;
  }
}

/* --------------------------------
 * Forced colors (Windows High Contrast)
 * -------------------------------- */
@media (forced-colors: active) {
  .accordion-item {
    border: var(--layout-border-thin) solid ButtonText;
  }

  .accordion-trigger {
    color: ButtonText;
  }

  .accordion-trigger:focus-visible {
    outline: 2px solid ButtonText;
    box-shadow: none;
  }

  .accordion-icon {
    color: ButtonText;
  }
}
